hooks.command:
#!/bin/bash
# Block staging raw data or the gbrain DB.
if git diff --cached --name-only 2>/dev/null | grep -E '(^|/)(data/|.*\.csv$|gbrain/store/.*\.db$|.*\.parquet$)'; then echo '[Hook] Refusing to stage data/artifact files. Add them to .gitignore.' >&2; exit 2; fi

#!/bin/bash
# Enforce the two-plane import boundary (see .claude/rules/common.md #2).
f="$CLAUDE_FILE_PATH"
case "$f" in
  */tagging/*.py) grep -nE 'import[[:space:]]+agent|from[[:space:]]+agent' "$f" && echo '[Hook] tagging/ must not import agent/.' >&2 ;;
  */agent/*.py) grep -nE 'import[[:space:]]+tagging|from[[:space:]]+tagging' "$f" && echo '[Hook] agent/ must not import tagging/. Read from gbrain instead.' >&2 ;;
esac
exit 0
